// 1. Acceso a datos del Webhook y Mensajes
const webhookData = $('Webhook GHL1').first().json.body;
const inputData = $input.first().json;

let rawMessages = [];
if (inputData && inputData.messages) {
  rawMessages = Array.isArray(inputData.messages) ? inputData.messages : (inputData.messages.messages || []);
}

// 2. Procesar historial y último mensaje
const historial = rawMessages
  .filter(m => m && m.body) 
  .slice(-10)
  .map(m => ({
    role: m.direction === 'inbound' ? 'user' : 'assistant',
    content: String(m.body).trim()
  }));

const ultimoMensaje = webhookData.message?.body || [...rawMessages].reverse().find(m => m.direction === 'inbound')?.body || "";

// --- Función auxiliar para campos GHL ---
const cleanGHL = (val) => Array.isArray(val) ? val[0] : (val || "");

// 3. MIX COMERCIAL - PRIORIDAD INQUILINO POTENCIAL
return [{
  json: {
    contactId: webhookData.contact_id || "",
    nombre: webhookData.full_name || webhookData.first_name || "Lead",

    // Identificación
    sku: cleanGHL(webhookData['Inquilino Potencial - SKU (Código de Habitación)']) || cleanGHL(webhookData['Inquilino Contrato - Código Habitación (SKU)']) || cleanGHL(webhookData['Inquilino Potencial - Ref. Habitacion']),

    // Datos Económicos
    precio: cleanGHL(webhookData['Inquilino Potencial - Precio habitacion Preguntada']),
    adminFee: cleanGHL(webhookData['Inquilino Potencial - Precio admin fee habitacion preguntada']),
    totalFianzaHonorarios: cleanGHL(webhookData['Inquilino Potencial - Suma Fianza + Honorarios']),

    // Ubicación y Multimedia
    direccion: cleanGHL(webhookData['Inquilino Contrato - Dirección de la propiedad alquilada']) || "Madrid/Alicante",
    linkIdealista: cleanGHL(webhookData['Inquilino Potencial - ¿Enlace habitación? ']),
    linkYoutube: cleanGHL(webhookData['Inquilino Potencial - Vídeo de Youtube']),

    // Conversación
    ultimoMensaje: String(ultimoMensaje).trim(),
    historial,

    // Estados IA
    nuevosIntentos: (parseInt(cleanGHL(webhookData['Chattyrental - IA_Respuestas_dadas'])) || 0) + 1,
    iaActiva: String(cleanGHL(webhookData['Chattyrental - IA_Activa'])).toUpperCase() === 'ON',
    iaBloqueada: String(cleanGHL(webhookData['Chattyrental - IA_Bloqueada_humano'])).toLowerCase() === 'true'
  }
}];

