const preparaData = $('Preparar Datos para IA1').first().json;
const memRaw = $input.first().json;
const memArr = Array.isArray(memRaw) ? memRaw : [];
let historial = preparaData.historial || [];
let supabaseMessages = [];
let supabaseMemoryId = null;
if (memArr.length > 0) {
  supabaseMemoryId = memArr[0].id;
  supabaseMessages = memArr[0].messages || [];
  if (supabaseMessages.length > 0) historial = supabaseMessages;
}
return [{ json: { ...preparaData, historial, supabaseMemoryId, supabaseMessages } }];

const mergeData = $('Merge Historial con Supabase').first().json;
const aiResponse = $input.first().json.output || '';
const existingMsgs = mergeData.supabaseMessages || [];
const newMsgs = [
  ...existingMsgs,
  { role: 'user', content: mergeData.ultimoMensaje, ts: new Date().toISOString() },
  { role: 'assistant', content: aiResponse, ts: new Date().toISOString() }
].slice(-20);
return [{ json: {
  contactId: mergeData.contactId,
  nombre: mergeData.nombre,
  ultimoMensaje: mergeData.ultimoMensaje,
  nuevosIntentos: mergeData.nuevosIntentos,
  supabaseMemoryId: mergeData.supabaseMemoryId,
  updatedMessages: newMsgs,
  aiResponse,
  esHandover: mergeData.nuevosIntentos >= 7
} }];

