const data = $('Construir Memoria Actualizada').first().json;
const response = data.aiResponse || '';
const ultimoMensaje = data.ultimoMensaje || '';
const frases = ['no tengo esa informacion','no se exactamente','no puedo confirmar',
  'habria que verificar','no tengo claro','te diria que preguntes','no tengo acceso','desconozco'];
const incertidumbre = frases.some(f => response.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').includes(f));
const esHandover = data.esHandover;
const msgs = data.updatedMessages || [];
const prevUser = msgs.slice(0, -2).filter(m => m.role === 'user').map(m => m.content);
const slice = ultimoMensaje.toLowerCase().slice(0, 25);
const preguntaRepetida = prevUser.some(p => p.toLowerCase().slice(0, 25) === slice);
return [{ json: {
  ...data,
  esLaguna: incertidumbre || esHandover || preguntaRepetida,
  tipoLaguna: esHandover ? 'handover' : preguntaRepetida ? 'repetida' : 'incertidumbre',
  pregunta: ultimoMensaje,
  respuestaIA: response
} }];

